8	function basePremiumFor(item: { type: string }): number {
9	  return BASE_PREMIUM_BY_TYPE[item.type];
10	}
11	
12	export function quote(_customer: { yearsWithMHPCO: number }, items: { type: string }[]): number {
13	  const itemsTotal = items.length === 0 ? 0 : basePremiumFor(items[0]);
14	  return itemsTotal + PROCESSING_FEE;
15	}
